import { GoogleAuth } from 'google-auth-library';

async function callGeminiWithExaGrounding() {
  const projectId = process.env.GOOGLE_CLOUD_PROJECT;
  const location = process.env.GOOGLE_CLOUD_LOCATION || 'us-central1';
  const exaApiKey = process.env.EXA_API_KEY;
  const modelId = 'gemini-2.5-flash'; // As specified in the prompt

  if (!projectId || !exaApiKey) {
    console.error('Please set GOOGLE_CLOUD_PROJECT and EXA_API_KEY environment variables.');
    process.exit(1);
  }

  // 1. Obtain Google Cloud Access Token
  // The GoogleAuth library automatically handles refreshing tokens.
  const auth = new GoogleAuth({
    scopes: 'https://www.googleapis.com/auth/cloud-platform', // Required scope for AI Platform
  });
  const client = await auth.getClient();
  const accessToken = (await client.getAccessToken()).token;

  if (!accessToken) {
    console.error('Failed to obtain Google Cloud access token. Ensure gcloud is authenticated.');
    process.exit(1);
  }

  const endpoint = `https://${location}-aiplatform.googleapis.com/v1/projects/${projectId}/locations/${location}/publishers/google/models/${modelId}:generateContent`;

  const requestBody = {
    contents: [
      {
        role: 'user',
        parts: [{ text: 'What are the latest advancements in AI in the last 6 months?' }],
      },
    ],
    tools: [
      {
        exaAiSearch: {
          api_key: exaApiKey,
          customConfigs: {
            type: 'auto', // 'auto' or 'fast' for Exa search type
            numResults: 5, // Maximum number of search results to use for grounding
            // includeDomains: ['techcrunch.com', 'wired.com'], // Optional: restrict search to specific domains
            contents: {
              highlights: {
                maxCharacters: 200, // Max characters for highlights from search results
              },
            },
          },
        },
      },
    ],
    // Optional: Configure generation parameters
    generationConfig: {
      temperature: 0.7,
      maxOutputTokens: 800,
    },
  };

  try {
    const response = await fetch(endpoint, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json; charset=utf-8',
      },
      body: JSON.stringify(requestBody),
    });

    if (!response.ok) {
      const errorData = await response.json();
      console.error(`Error: ${response.status} ${response.statusText}`, errorData);
      return;
    }

    const data = await response.json();
    console.log('Gemini Response with Exa Grounding:');
    console.log(JSON.stringify(data, null, 2));

    // Extract and print the generated text
    const generatedText = data.candidates?.[0]?.content?.parts?.[0]?.text;
    if (generatedText) {
      console.log('\nGenerated Text:');
      console.log(generatedText);
    }

    // Extract and print grounding metadata (e.g., search queries, citations)
    const groundingMetadata = data.candidates?.[0]?.groundingMetadata;
    if (groundingMetadata) {
      console.log('\nGrounding Metadata:');
      console.log(JSON.stringify(groundingMetadata, null, 2));
    }

  } catch (error) {
    console.error('Failed to call Gemini API:', error);
  }
}

callGeminiWithExaGrounding();
